function f(n,i){if(!n||!i)return"—";const e=new Date(i).getTime()-new Date(n).getTime();if(!Number.isFinite(e)||e<0)return"—";const t=Math.round(e/1e3),u=Math.floor(t/3600),r=Math.floor(t%3600/60),o=t%60;return u>0?`${u}h ${r}m ${o}s`:r>0?`${r}m ${o}s`:`${o}s`}function m(n,i=Date.now()){if(!n)return"";const e=new Date(n).getTime();if(!Number.isFinite(e))return"";const t=Math.round((i-e)/1e3);if(t<0)return"just now";const u=[[60,1,"second"],[3600,60,"minute"],[86400,3600,"hour"],[2592e3,86400,"day"],[31536e3,2592e3,"month"],[1/0,31536e3,"year"]];if(t<45)return"just now";for(const[r,o,a]of u)if(t<r){const s=Math.round(t/o);return`${s} ${a}${s===1?"":"s"} ago`}return""}export{f,m as r};
